// Extract AI-generated content and format for Next.js markdown blog
const items = $input.all();
const processedItems = [];

for (const item of items) {
  const aiOutput = item.json.output || item.json.text || '';

  // Extract title (first line or marked with Title:)
  let title = '';
  let content = aiOutput;

  // Try to extract title from various formats
  const titleMatch = aiOutput.match(/^(?:Title:|#)\s*(.+?)(?:\n|$)/i);
  if (titleMatch) {
    title = titleMatch[1].trim();
    content = aiOutput.replace(/^(?:Title:|#)\s*.+?(?:\n|$)/i, '').trim();
  } else {
    // Use first line as title if no marker
    const lines = aiOutput.split('\n');
    title = lines[0].trim().replace(/^#+\s*/, '');
    content = lines.slice(1).join('\n').trim();
  }

  // Clean the title
  let cleanTitle = title.replace(/[^a-zA-Z0-9\s-]/g, '').replace(/\s+/g, ' ').trim();

  // Limit title to 20 characters
  if (cleanTitle.length > 20) {
    cleanTitle = cleanTitle.substring(0, 20).trim();
  }

  // Generate slug from title (for filename)
  let slug = cleanTitle
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');

  // Limit slug to 20 characters
  if (slug.length > 20) {
    slug = slug.substring(0, 20).replace(/-$/, '');
  }

  // Get current date in YYYY-MM-DD format
  const today = new Date();
  const dateStr = today.toISOString().split('T')[0];

  // Ensure content is proper markdown (clean up any HTML)
  let markdownContent = content
    .replace(/<p>/g, '')
    .replace(/<\/p>/g, '\n\n')
    .replace(/<strong>(.+?)<\/strong>/g, '**$1**')
    .replace(/<em>(.+?)<\/em>/g, '*$1*')
    .replace(/<h2>(.+?)<\/h2>/g, '## $1')
    .replace(/<h3>(.+?)<\/h3>/g, '### $1')
    .replace(/<ul>/g, '')
    .replace(/<\/ul>/g, '\n')
    .replace(/<li>(.+?)<\/li>/g, '- $1\n')
    .replace(/<a href="(.+?)">(.+?)<\/a>/g, '[$2]($1)')
    .trim();

  // Create frontmatter (image will be added later)
  const frontmatter = `---\ntitle: "${cleanTitle}"\ndate: "${dateStr}"\nslug: "${slug}"\n---\n\n`;

  // Combine frontmatter and content
  const fullMarkdown = frontmatter + markdownContent;

  // Base64 encode for GitHub API
  const base64Content = Buffer.from(fullMarkdown, 'utf8').toString('base64');

  processedItems.push({
    json: {
      ...item.json,
      title: cleanTitle,
      slug: slug,
      date: dateStr,
      filename: `${slug}.md`,
      content: markdownContent,
      fullMarkdown: fullMarkdown,
      base64Content: base64Content,
      filePath: `content/blog/${slug}.md`
    }
  });
}

return processedItems;

// Generate image prompt from blog post title
const items = $input.all();
const processedItems = [];

for (const item of items) {
  const title = item.json.title || '';
  const content = item.json.content || '';

  // Extract key themes from content (first 200 chars)
  const contentPreview = content.substring(0, 200).toLowerCase();

  // Create a descriptive image prompt
  let imagePrompt = `A professional, modern illustration representing: ${title}. `;

  // Add context based on common AI/Cloud themes
  if (contentPreview.includes('ai') || contentPreview.includes('artificial intelligence')) {
    imagePrompt += 'Style: futuristic, tech-forward, with AI and machine learning visual elements. ';
  }
  if (contentPreview.includes('cloud') || contentPreview.includes('migration')) {
    imagePrompt += 'Include cloud computing and digital transformation themes. ';
  }
  if (contentPreview.includes('enterprise') || contentPreview.includes('business')) {
    imagePrompt += 'Professional business context, suitable for enterprise technology leaders. ';
  }

  imagePrompt += 'Color scheme: modern tech colors (blues, purples, gradients). Clean, minimalist design suitable for a blog header image. 16:9 aspect ratio, high quality.';

  // Limit slug for image filename (slug is already max 20 chars, so total will be 32 chars max)
  let imageSlug = item.json.slug || '';
  // Slug is already limited to 20, so image filename will be max 32 characters (20 + '-header.jpg')
  if (imageSlug.length > 20) {
    imageSlug = imageSlug.substring(0, 20).replace(/-$/, '');
  }

  processedItems.push({
    json: {
      ...item.json,
      imagePrompt: imagePrompt,
      imageFilename: `${imageSlug}-header.jpg`
    }
  });
}

return processedItems;

