// Extract SHA from GitHub response and merge with original data
// Handles both 200 (file exists) and 404 (file doesn't exist) responses
// Also handles case where HTTP Request node fails
const items = $input.all();
const processedItems = [];

// Get original data from previous node
const originalItem = $('Add Image to Frontmatter').first();

// If no items received (HTTP Request failed), use original item directly
if (!items || items.length === 0) {
  if (originalItem && originalItem.json) {
    processedItems.push({
      json: {
        ...originalItem.json,
        fileSha: ''
      }
    });
  }
  return processedItems;
}

for (const item of items) {
  let sha = '';

  try {
    // Check if response has SHA (file exists)
    // GitHub returns sha field when file exists (status 200)
    // When file doesn't exist (404), response has message field instead
    if (item.json && item.json.sha && typeof item.json.sha === 'string') {
      sha = item.json.sha;
    }
    // If response has error message (404) or is empty, sha remains empty string (new file)
  } catch (error) {
    // If there's any error accessing the response, treat as new file (empty sha)
    console.log('Error extracting SHA, treating as new file:', error.message);
    sha = '';
  }

  // Merge original data with SHA
  // Always ensure we have the original data even if SHA extraction failed
  if (originalItem && originalItem.json) {
    processedItems.push({
      json: {
        ...originalItem.json,
        fileSha: sha
      }
    });
  } else if (item && item.json) {
    // Fallback if original item not found
    processedItems.push({
      json: {
        ...item.json,
        fileSha: sha
      }
    });
  }
}

return processedItems;
